sys_script_include.script:
function RenderDateTimeLocal(vDateTime)
{
	if (vDateTime === false || vDateTime == null || vDateTime == undefined)
	{
		return '';
	}

	if (GetType(vDateTime) == 'number')
	{
		var nTimeStamp = GetIntegerValue(vDateTime);

		var strResult = RunScriptInGlobalScope(
			"var tz = gs.getSession().getTimeZone();"+
			"var gdt = new GlideDateTime();"+
			"gdt.setValue(param1);"+
			"gdt.setTZ(tz);"+ 
			"result = gdt.getDisplayValueInternal();",
			nTimeStamp);
		return strResult;
	}

	strDateTime = GetStringValue(vDateTime);

	var nTimestamp = ParseDateTime(strDateTime);
	if (nTimeStamp === false)
	{
		return '';
	}
	return RenderDateTimeLocal(nTimestamp);
}
